```class Solution {
public:
    bool canPartitionKSubsets(vector<int>& nums, int k) {
        int sum = accumulate(nums.begin(), nums.end(), 0);
        vector<bool> dp(sum + 1, false);

        for (int i = 0; i < nums.size(); i++) {
            dp[nums[i] + 1] = true;
        }

        for (int i = sum - 1; i >= 0; i--) {
            for (int j = 0; j < k; j++) {
                if (dp[i] && (i % nums[j] == 0)) {
                    dp[i / nums[j]] = true;
                }
            }
        }

        return dp[0];
    }
};
